import random

class System:
    def __init__(self, id):
        self.id = id
        self.infected = False

    def infect(self):
        self.infected = True

    def is_infected(self):
        return self.infected

class Malware:
    def __init__(self):
        self.systems = []

    def spread(self, system):
        if not system.is_infected():
            system.infect()
            self.spread_to_neighbors(system)

    def spread_to_neighbors(self, system):
        for neighbor in self.systems:
            if neighbor!= system and not neighbor.is_infected():
                self.spread(neighbor)

    def add_system(self, system):
        self.systems.append(system)

    def run(self):
        for system in self.systems:
            if not system.is_infected():
                self.spread(system)

# Create a network of systems
systems = [System(i) for i in range(10)]

# Create a malware instance and add systems to it
malware = Malware()
for system in systems:
    malware.add_system(system)

# Run the malware
malware.run()

# Print the infected systems
for system in systems:
    if system.is_infected():
        print(f"System {system.id} is infected")
    else:
        print(f"System {system.id} is not infected")
